SELECT "admin" AS store, "base" AS website, "Default" AS attribute_set, "configurable" AS type, [Item.model item no_] & "-" & [Item.variable code 01] AS sku, "size" AS configurable_attributes, "" AS associated, "" AS super_attribute_pricing, [Variable Code].description AS color_description, "" AS [size], 1 AS has_option, Item_1.[Description 2] AS name, "" AS category_ids, "" AS meta_title, "" AS meta_description, "/" & UCase(SubstSlashDash([Item.model item no_]) & "_" & [Item.Variable Code 01] & "_01") & ".jpg" AS [image], "" AS image_label, "/" & UCase(SubstSlashDash([Item.model item no_]) & "_" & [Item.Variable Code 01] & "_01") & ".jpg" AS small_image, "" AS small_image_label, "/" & UCase(SubstSlashDash([Item.model item no_]) & "_" & [Item.Variable Code 01] & "_01") & ".jpg" AS thumbnail, "" AS thumnail_label, UCase("/" & SubstSlashDash([Item.model item no_]) & "_" & [Item.Variable Code 01] & "_02") & ".jpg,/" & UCase(SubstSlashDash([Item.model item no_]) & "_" & [Item.Variable Code 01] & "_03") & ".jpg" & UCase(",/" & SubstSlashDash([Item.model item no_]) & "_" & [Item.Variable Code 01] & "_04") & ".jpg" AS media_gallery, 5 AS tax_class_id, SuggestedRetailPrices.SRP AS price, "" AS special_price, Val([Item.Gross Weight])*1000 AS weight, Item_1.Description AS description, Item_1.Description AS short_description, "" AS [""], "" AS related, "" AS manufacturer, "" AS [" "], 0 AS qty, 1 AS is_in_stock, 0 AS backorders, 1 AS manage_stock, "Abilitato" AS status, "Catalogo,Ricerca" AS visibility, "" AS materiale_suola_interna, "" AS materiale_suola, "" AS materiale_fodera, Item.[product sex] AS gender, Item.[collection code] AS collezione, [Item.model item no_] & "-" & [Item.variable code 01] AS codice_materiale_colore, "" AS ean_code, "" AS materiale, Item.[product family] AS tipologia_scarpa, Item.[Country_Region of Origin Code] AS [paese produzione], LCase([item.description 2] & "-" & Right$([item.model item no_],Len([ITEM.MODEL ITEM NO_])-InStr([item.model item no_],"/")) & "-" & SUBSTSLASHDASH([Item.variable code 01])) AS url_key, [item.tariff no_] AS tariffa_doganale, [item.upper composition] AS upper_composition, [item.lining composition] AS lining_composition, [item.outsole composition] AS outsole_composition, [item.insole composition] AS insole_composition
FROM (([Sales Line] INNER JOIN [Sales Header] ON [Sales Line].[Document No_] = [Sales Header].No_) INNER JOIN (((Item INNER JOIN Item AS Item_1 ON Item.[Model Item No_] = Item_1.No_) INNER JOIN SuggestedRetailPrices ON Item.No_ = SuggestedRetailPrices.[Item No_]) LEFT JOIN EanCodes ON Item.No_ = EanCodes.[Item No_]) ON [Sales Line].No_ = Item.No_) INNER JOIN [Variable Code] ON ([Sales Line].[Variable Code 01] = [Variable Code].[Variable Code]) AND ([Sales Line].[Variable Group 01] = [Variable Code].[Variable Group])
WHERE (((Item.[Advertising Material])=0))
GROUP BY "admin", "base", "Default", "configurable", "size", [Variable Code].description, Item_1.[Description 2], "/" & UCase(SubstSlashDash([Item.model item no_]) & "_" & [Item.Variable Code 01] & "_01") & ".jpg", UCase("/" & SubstSlashDash([Item.model item no_]) & "_" & [Item.Variable Code 01] & "_02") & ".jpg,/" & UCase(SubstSlashDash([Item.model item no_]) & "_" & [Item.Variable Code 01] & "_03") & ".jpg" & UCase(",/" & SubstSlashDash([Item.model item no_]) & "_" & [Item.Variable Code 01] & "_04") & ".jpg", 5, SuggestedRetailPrices.SRP, Val([Item.Gross Weight])*1000, Item_1.Description, 0, 1, "Abilitato", "Catalogo,Ricerca", Item.[product sex], Item.[collection code], [Item.model item no_] & "-" & [Item.variable code 01], "", Item.[product family], Item.[Country_Region of Origin Code], LCase([item.description 2] & "-" & Right$([item.model item no_],Len([ITEM.MODEL ITEM NO_])-InStr([item.model item no_],"/")) & "-" & SUBSTSLASHDASH([Item.variable code 01])), [item.tariff no_], [item.upper composition], [item.lining composition], [item.outsole composition], [item.insole composition], "/" & UCase(SubstSlashDash([Item.model item no_]) & "_" & [Item.Variable Code 01] & "_01") & ".jpg", "", "", "", "", "", "", "", "", "/" & UCase(SubstSlashDash([Item.model item no_]) & "_" & [Item.Variable Code 01] & "_01") & ".jpg", "", "", Item_1.Description, "", "", "", "", 1, 0, 1, "", "", "", [Item.model item no_] & "-" & [Item.variable code 01], "", "", "", "", "", "", [Item.model item no_] & "-" & [Item.variable code 01], "", [Sales Line].Type, [Sales Header].No_, [Sales Line].[Delete Reason]
HAVING ((([Sales Line].Type)=2) AND (([Sales Header].No_)=[forms]![principale]![FiltroODVEAN]) AND (([Sales Line].[Delete Reason])=""));

